import React, {useState} from 'react';
import Modal from '../components/Modal';

const demoLoans = [
  {id:1,member:'John Doe',amount:5000,type:'Personal',date:'2024-12-20',status:'Pending',savings:2500},
  {id:2,member:'Jane Smith',amount:15000,type:'Business',date:'2024-12-19',status:'Pending',savings:12000},
  {id:3,member:'Mike Johnson',amount:3000,type:'Education',date:'2024-12-18',status:'Pending',savings:1500}
];

const LoanApprovals = ()=>{
  const [loans,setLoans] = useState(demoLoans);
  const [selected, setSelected] = useState(null);
  const [remarks, setRemarks] = useState('');

  const approve = (id)=>{
    setLoans(l=>l.map(x=> x.id===id? {...x,status:'Approved'}:x));
    setSelected(null);
  }
  const reject = (id)=>{
    setLoans(l=>l.map(x=> x.id===id? {...x,status:'Rejected'}:x));
    setSelected(null);
  }

  return (
    <div>
      <h3>Loan Approvals</h3>
      <div className="card" style={{marginTop:12}}>
        <div className="small-muted">Pending Requests: {loans.filter(l=>l.status==='Pending').length}</div>
      </div>

      <div style={{marginTop:12}} className="table">
        <table>
          <thead>
            <tr><th>Member</th><th>Amount</th><th>Type</th><th>Date</th><th>Status</th><th>Actions</th></tr>
          </thead>
          <tbody>
            {loans.map(l=> (
              <tr key={l.id}>
                <td>{l.member}</td>
                <td>${l.amount.toLocaleString()}</td>
                <td>{l.type}</td>
                <td>{l.date}</td>
                <td>{l.status}</td>
                <td>
                  {l.status==='Pending' && (
                    <>
                      <button className="btn secondary" onClick={()=>setSelected(l)}>Review</button>
                    </>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {selected && (
        <Modal title={`Review Loan — ${selected.member}`} onClose={()=>setSelected(null)}>
          <div style={{marginBottom:8}}><strong>Amount:</strong> ${selected.amount}</div>
          <div style={{marginBottom:8}}><strong>Member Savings:</strong> ${selected.savings}</div>
          <div style={{marginBottom:8}}>
            <label>Admin Remarks</label>
            <textarea className="input" value={remarks} onChange={e=>setRemarks(e.target.value)} style={{height:80}} />
          </div>
          <div style={{display:'flex',gap:8,justifyContent:'flex-end'}}>
            <button className="btn secondary" onClick={()=>{reject(selected.id);}}>Reject</button>
            <button className="btn" onClick={()=>{approve(selected.id);}}>Approve</button>
          </div>
        </Modal>
      )}

    </div>
  );
}
export default LoanApprovals;
